+fn render_replay_command(
+    command_line: &str,
+    command_runner: Option<&str>,
+    environment: &BTreeMap<String, String>,
+) -> String {
+    let mut parts = Vec::new();
+
+    if !environment.is_empty() {
+        parts.push("env --".to_owned());
+        for (key, value) in environment {
+            parts.push(shell_quote(&format!("{key}={value}")));
+        }
+    }
+
+    if let Some(runner) = command_runner {
+        parts.extend(shell_split_prefix(runner));
+    }
+
+    parts.push("bash".to_owned());
+    parts.push("-lc".to_owned());
+    parts.push(shell_quote(command_line));
+    parts.join(" ")
+}
+
+fn shell_split_prefix(prefix: &str) -> Vec<String> {
+    let trimmed = prefix.trim();
+    if trimmed.is_empty() {
+        return Vec::new();
+    }
+
+    let mut parts = Vec::new();
+    let mut current = String::new();
+    let mut chars = trimmed.chars();
+    let mut in_single = false;
+    let mut in_double = false;
+    let mut escaped = false;
+
+    while let Some(ch) = chars.next() {
+        if escaped {
+            current.push(ch);
+            escaped = false;
+            continue;
+        }
+
+        if in_single {
+            if ch == '\'' {
+                in_single = false;
+            } else {
+                current.push(ch);
+            }
+            continue;
+        }
+
+        if in_double {
+            match ch {
+                '"' => in_double = false,
+                '\\' => {
+                    if let Some(next) = chars.next() {
+                        current.push(next);
+                    } else {
+                        escaped = true;
+                    }
+                }
+                _ => current.push(ch),
+            }
+            continue;
+        }
+
+        match ch {
+            '\'' => in_single = true,
+            '"' => in_double = true,
+            '\\' => escaped = true,
+            ch if ch.is_whitespace() => {
+                if !current.is_empty() {
+                    parts.push(std::mem::take(&mut current));
+                }
+            }
+            _ => current.push(ch),
+        }
+    }
+
+    if escaped || in_single || in_double {
+        return vec![trimmed.to_owned()];
+    }
+    if !current.is_empty() {
+        parts.push(current);
+    }
+
+    parts.into_iter().map(|part| shell_quote(&part)).collect()
+}
+
+fn shell_quote(value: &str) -> String {
+    if value.is_empty() {
+        return "''".to_owned();
+    }
+    format!("'{}'", value.replace('\'', "'\"'\"'"))
+}
